parameters.jsCode:
// This script handles ANY dynamic form fields without failing.
// It collects all input fields and returns them as clean key–value pairs.

const output = [];

for (const item of $input.all()) {
  const data = {};

  // Copy all form fields dynamically
  for (const key of Object.keys(item.json)) {
    data[key] = item.json[key];
  }

  // 🔥 Map long question names to clean answer keys
  data.answer1 = item.json["Can you describe a specific project from your previous roles where you successfully utilized skills that align with the core requirements of this job?"];
  data.answer2 = item.json["What were your main responsibilities in your last position, and what key achievements are you most proud of that would be applicable to this role?"];
  data.answer3 = item.json["Which technical or soft skills do you consider most relevant to this position, and how have you demonstrated these skills in a professional setting?"];
  data.answer4 = item.json["How do your professional values and career goals align with our company’s mission and culture, and what motivates you to contribute to our team?"];
  data.answer5 = item.json["Can you provide an example of a challenging situation you faced at work, how you approached solving it, and the outcome?"];

  output.push({ json: data });
}

// Return final output
return output;

